code = """import json

# Load citations for physical activity papers
cite_file = locals()['var_functions.query_db:58']
with open(cite_file, 'r') as f:
    citations = json.load(f)

print(f"Total citations loaded: {len(citations)}")

# Filter for papers published in 2016 based on citation_year
# If a paper has citations in 2016, it was published in 2016 or earlier
papers_2016 = {}

for rec in citations:
    title = rec['title']
    citation_year = int(rec['citation_year'])
    citation_count = int(rec['citation_count'])
    
    if citation_year == 2016:
        if title not in papers_2016:
            papers_2016[title] = 0
        papers_2016[title] += citation_count

print(f"Papers with citations in 2016: {len(papers_2016)}")

# Get total citations for these papers
# Need to load all citations again to sum them
cite_all_file = locals()['var_functions.query_db:4']
with open(cite_all_file, 'r') as f:
    all_citations = json.load(f)

citation_totals = {}
for rec in all_citations:
    title = rec['title']
    count = int(rec['total_citations'])
    citation_totals[title] = count

# Combine results
final_results = []
for title, citations_2016 in papers_2016.items():
    if title in citation_totals:
        final_results.append({
            'title': title,
            'total_citations': citation_totals[title]
        })

print(f"Papers with 2016 citations: {len(final_results)}")
for paper in final_results[:10]:
    print(f"{paper['title']}: {paper['total_citations']} total citations")

result = json.dumps(final_results)
print('__RESULT__:')
print(result)"""

